import React, { useRef, useState } from 'react';

interface CameraCaptureProps {
  onCapture: (base64: string) => void;
}

export const CameraCapture: React.FC<CameraCaptureProps> = ({ onCapture }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [preview, setPreview] = useState<string | null>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        setPreview(base64String);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleConfirm = () => {
    if (preview) {
      // Remove data URL prefix for API
      const base64Data = preview.split(',')[1];
      onCapture(base64Data);
    }
  };

  const handleRetake = () => {
    setPreview(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 flex flex-col items-center justify-center min-h-[50vh]">
      {!preview ? (
        <div 
            className="w-full h-80 border-2 border-dashed border-gray-300 rounded-2xl flex flex-col items-center justify-center bg-gray-50 cursor-pointer hover:bg-gray-100 transition-colors"
            onClick={() => fileInputRef.current?.click()}
        >
          <div className="w-16 h-16 rounded-full bg-brand-green/10 flex items-center justify-center mb-4 text-brand-green">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </div>
          <p className="text-gray-500 font-medium">Tap to take photo</p>
          <input
            type="file"
            accept="image/*"
            capture="environment"
            ref={fileInputRef}
            className="hidden"
            onChange={handleFileChange}
          />
        </div>
      ) : (
        <div className="w-full flex flex-col items-center">
            <div className="relative w-full h-80 rounded-2xl overflow-hidden shadow-md mb-6">
                <img src={preview} alt="Crop Preview" className="w-full h-full object-cover" />
            </div>

            <div className="flex gap-4 w-full">
                <button 
                    onClick={handleRetake}
                    className="flex-1 py-3 px-4 rounded-xl border border-gray-300 text-gray-700 font-semibold hover:bg-gray-50"
                >
                    Retake
                </button>
                <button 
                    onClick={handleConfirm}
                    className="flex-1 py-3 px-4 rounded-xl bg-brand-green text-white font-semibold shadow-md hover:bg-opacity-90"
                >
                    Analyze Crop
                </button>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { DiagnosisResult, SupportedLanguage } from '../types';
import { generateSpeech } from '../services/geminiService';

interface DiagnosisReportProps {
  result: DiagnosisResult;
  language: SupportedLanguage;
  onReset: () => void;
}

export const DiagnosisReport: React.FC<DiagnosisReportProps> = ({ result, language, onReset }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBuffer, setAudioBuffer] = useState<AudioBuffer | null>(null);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);

  useEffect(() => {
    // Pre-load audio when component mounts
    const loadAudio = async () => {
      setIsLoadingAudio(true);
      const textToRead = `${result.crop}. ${result.diagnosis}. ${result.description}`;
      const buffer = await generateSpeech(textToRead, language);
      setAudioBuffer(buffer);
      setIsLoadingAudio(false);
    };
    loadAudio();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [result, language]);

  const playAudio = () => {
    if (!audioBuffer) return;

    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
    const source = audioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(audioContext.destination);
    source.onended = () => setIsPlaying(false);
    source.start(0);
    setIsPlaying(true);
  };

  const severityColor = {
    'Low': 'bg-yellow-100 text-yellow-800',
    'Medium': 'bg-orange-100 text-orange-800',
    'High': 'bg-red-100 text-red-800',
    'None': 'bg-green-100 text-green-800'
  }[result.severity] || 'bg-gray-100 text-gray-800';

  return (
    <div className="max-w-md mx-auto p-4 pb-20">
      {/* Audio Player Banner */}
      <div className="bg-brand-green text-white p-4 rounded-2xl shadow-lg mb-6 flex items-center justify-between">
        <div>
          <h3 className="font-semibold text-sm opacity-90">Listen to Report</h3>
          <p className="text-xs opacity-75">{language}</p>
        </div>
        <button 
          onClick={playAudio}
          disabled={isLoadingAudio || !audioBuffer}
          className="w-12 h-12 rounded-full bg-white/20 flex items-center justify-center hover:bg-white/30 transition disabled:opacity-50"
        >
          {isLoadingAudio ? (
            <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
          ) : isPlaying ? (
             <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 9v6m4-6v6m7-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
            </svg>
          )}
        </button>
      </div>

      {/* Main Diagnosis */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
        <div className="p-5">
          <div className="flex justify-between items-start mb-2">
            <div>
              <p className="text-sm text-gray-500 uppercase font-semibold tracking-wider">{result.crop}</p>
              <h2 className="text-2xl font-bold text-gray-900">{result.diagnosis}</h2>
            </div>
            <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide ${severityColor}`}>
              {result.severity} Risk
            </span>
          </div>
          <p className="text-gray-700 leading-relaxed mt-2">{result.description}</p>
        </div>
      </div>

      {/* Action Plan */}
      <h3 className="font-bold text-lg text-gray-800 mb-3 px-1">Treatment Plan</h3>

      <div className="space-y-4">
        {/* Organic */}
        <div className="bg-white p-5 rounded-2xl shadow-sm border border-l-4 border-l-brand-green border-gray-100">
          <div className="flex items-center gap-2 mb-3">
             <div className="p-1.5 bg-green-100 rounded-lg text-brand-green">
               <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M6.267 3.455a3.066 3.066 0 001.745-.723 3.066 3.066 0 013.976 0 3.066 3.066 0 001.745.723 3.066 3.066 0 012.812 2.812c.051.643.304 1.254.723 1.745a3.066 3.066 0 010 3.976 3.066 3.066 0 00-.723 1.745 3.066 3.066 0 01-2.812 2.812 3.066 3.066 0 00-1.745.723 3.066 3.066 0 01-3.976 0 3.066 3.066 0 00-1.745-.723 3.066 3.066 0 01-2.812-2.812 3.066 3.066 0 00-.723-1.745 3.066 3.066 0 010-3.976 3.066 3.066 0 00.723-1.745 3.066 3.066 0 012.812-2.812zm7.44 5.252a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
               </svg>
             </div>
             <h4 className="font-semibold text-gray-900">Organic Solution</h4>
          </div>
          <ul className="space-y-2">
            {result.advice.organic.map((step, i) => (
              <li key={i} className="flex gap-3 text-gray-700 text-sm">
                <span className="font-bold text-brand-green">{i + 1}.</span>
                <span>{step}</span>
              </li>
            ))}
          </ul>
        </div>

        {/* Chemical */}
        {result.advice.chemical.length > 0 && (
          <div className="bg-white p-5 rounded-2xl shadow-sm border border-l-4 border-l-brand-orange border-gray-100">
            <div className="flex items-center gap-2 mb-3">
              <div className="p-1.5 bg-orange-100 rounded-lg text-brand-orange">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M7 2a1 1 0 00-.707 1.707L7 4.414v3.758a1 1 0 01-.293.707l-4 4C.817 14.761 2.154 18 5.06 18h9.879c2.906 0 4.244-3.239 2.353-5.121l-4-4A1 1 0 0113 8.172V4.414l.707-.707A1 1 0 0013 2H7zm2 6.172V4h2v4.172a3 3 0 00.879 2.12l1.027 1.028a4 4 0 00-2.171.102l-.47.156a4 4 0 01-2.53 0l-.563-.187a4 4 0 00-2.329.313l.83-824a3 3 0 00.879-2.12z" clipRule="evenodd" />
                </svg>
              </div>
              <h4 className="font-semibold text-gray-900">Chemical Solution</h4>
            </div>
            <ul className="space-y-2">
              {result.advice.chemical.map((step, i) => (
                <li key={i} className="flex gap-3 text-gray-700 text-sm">
                  <span className="font-bold text-brand-orange">{i + 1}.</span>
                  <span>{step}</span>
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>

      <button 
        onClick={onReset}
        className="w-full mt-8 py-3.5 bg-gray-900 text-white rounded-xl font-semibold shadow-lg active:scale-95 transition-transform"
      >
        Scan Another Crop
      </button>
    </div>
  );
};

import React, { useState } from 'react';
import { AppState, SupportedLanguage, DiagnosisResult } from './types';
import { Header } from './components/Header';
import { CameraCapture } from './components/CameraCapture';
import { LanguageSelector } from './components/LanguageSelector';
import { DiagnosisReport } from './components/DiagnosisReport';
import { analyzeCropImage } from './services/geminiService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.HOME);
  const [language, setLanguage] = useState<SupportedLanguage>(SupportedLanguage.ENGLISH);
  const [diagnosisResult, setDiagnosisResult] = useState<DiagnosisResult | null>(null);

  const handleCapture = async (base64Image: string) => {
    setAppState(AppState.ANALYZING);
    try {
      const result = await analyzeCropImage(base64Image, language);
      setDiagnosisResult(result);
      setAppState(AppState.RESULT);
    } catch (error) {
      console.error(error);
      alert("Failed to analyze image. Please ensure you are connected to the internet.");
      setAppState(AppState.HOME);
    }
  };

  const renderContent = () => {
    switch (appState) {
      case AppState.HOME:
        return (
          <div className="px-4 pb-12 pt-6 max-w-md mx-auto">
            {/* Hero Section */}
            <div className="text-center mb-8">
              <h1 className="text-3xl font-bold text-gray-900 mb-2">
                Your Digital <br/>
                <span className="brand-orange">Crop Doctor</span>
              </h1>
              <p className="text-gray-600 mb-6">
                Bridging the knowledge gap for African farmers with AI-driven intelligence.
              </p>

              <LanguageSelector selected={language} onChange={setLanguage} />
            </div>

            {/* Feature Cards */}
            <div className="grid grid-cols-2 gap-4 mb-8">
              <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center text-center">
                <div className="w-10 h-10 rounded-full bg-brand-green/10 flex items-center justify-center text-brand-green mb-2">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /></svg>
                </div>
                <h3 className="font-semibold text-sm">Instant Diagnosis</h3>
              </div>
              <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center text-center">
                <div className="w-10 h-10 rounded-full bg-brand-orange/10 flex items-center justify-center text-brand-orange mb-2">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
                </div>
                <h3 className="font-semibold text-sm">Voice Support</h3>
              </div>
            </div>

            {/* CTA */}
            <button
              onClick={() => setAppState(AppState.CAMERA)}
              className="w-full py-4 bg-brand-green text-white rounded-xl font-bold text-lg shadow-lg hover:shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
              Start New Diagnosis
            </button>

            {/* Supported Crops */}
            <div className="mt-10">
              <h4 className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-4 text-center">Supported Crops</h4>
              <div className="flex flex-wrap justify-center gap-3 opacity-60">
                 {['Maize', 'Rice', 'Cassava', 'Tomato', 'Pepper', 'Onion'].map(crop => (
                   <span key={crop} className="px-3 py-1 bg-gray-200 rounded-md text-xs font-semibold text-gray-600">{crop}</span>
                 ))}
              </div>
            </div>
          </div>
        );
      case AppState.CAMERA:
        return <CameraCapture onCapture={handleCapture} />;
      case AppState.ANALYZING:
        return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] px-4 text-center">
            <div className="w-20 h-20 border-4 border-brand-orange border-t-transparent rounded-full animate-spin mb-6"></div>
            <h2 className="text-xl font-bold text-gray-800 mb-2">Analyzing Crop...</h2>
            <p className="text-gray-500 max-w-xs">Our AI Doctor is examining the leaves for signs of disease.</p>
          </div>
        );
      case AppState.RESULT:
        return diagnosisResult ? (
          <DiagnosisReport 
            result={diagnosisResult} 
            language={language} 
            onReset={() => setAppState(AppState.HOME)} 
          />
        ) : null;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-safe">
      <Header onHome={() => setAppState(AppState.HOME)} />
      <main>
        {renderContent()}
      </main>
    </div>
  );
};

export default App;

export enum AppState {
  HOME = 'HOME',
  CAMERA = 'CAMERA',
  ANALYZING = 'ANALYZING',
  RESULT = 'RESULT',
  CHAT = 'CHAT',
  ERROR = 'ERROR'
}

export enum SupportedLanguage {
  ENGLISH = 'English',
  HAUSA = 'Hausa',
  YORUBA = 'Yoruba',
  IGBO = 'Igbo',
  SWAHILI = 'Swahili'
}

export interface DiagnosisResult {
