import { GoogleGenAI, Modality, Chat, GenerateContentResponse } from "@google/genai";
import { SupportedLanguage, DiagnosisResult } from "../types";

// Initialize the Gemini AI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Analyzes a crop image using Gemini Vision to detect diseases.
 */
export const analyzeCropImage = async (
  base64Image: string,
  language: SupportedLanguage
): Promise<DiagnosisResult> => {
  try {
    const prompt = `
      You are Noma AI, an expert agricultural Digital Crop Doctor for African farmers.
      Analyze the provided image of a crop. 
      1. Identify the crop (Focus on African staples like Maize, Rice, Cassava, Tomato, Pepper, Onion).
      2. Detect any diseases, pests, or nutrient deficiencies.
      3. If the plant is healthy, state that.
      4. Provide actionable advice for organic and chemical treatments suitable for African contexts.

      IMPORTANT: Translate the ENTIRE output values into ${language}.

      Return ONLY a valid JSON object with this specific structure (do not add markdown code blocks):
      {
        "crop": "Name of the crop",
        "status": "Healthy" or "Infected" or "Unknown",
        "diagnosis": "Name of the disease/pest or 'Healthy'",
        "severity": "Low", "Medium", "High", or "None",
        "description": "A simple explanation of the condition (2-3 sentences)",
        "advice": {
          "organic": ["Step 1", "Step 2"],
          "chemical": ["Step 1", "Step 2"],
          "prevention": ["Tip 1", "Tip 2"]
        }
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image
            }
          },
          { text: prompt }
        ]
      },
      config: {
        temperature: 0.4,
      }
    });

    const text = response.text || "{}";
    // Clean up markdown if present
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleanText) as DiagnosisResult;

  } catch (error) {
    console.error("Analysis failed:", error);
    throw new Error("Failed to analyze the crop. Please try again.");
  }
};

/**
 * Generates audio from text using Gemini TTS.
 */
export const generateSpeech = async (text: string, language: SupportedLanguage): Promise<AudioBuffer | null> => {
  try {
    const voiceName = 'Kore'; 

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: voiceName },
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    // Decode audio
    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      audioContext,
      24000,
      1
    );

    return audioBuffer;
  } catch (error) {
    console.error("TTS failed:", error);
    return null;
  }
};

/**
 * Creates a chat session for the Agri Advisor.
 */
export const createChatSession = (): Chat => {
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: "You are Noma, a friendly and knowledgeable agricultural expert assisting African farmers. You provide advice on crop management, pest control, weather interpretation, and market trends. Keep answers practical, concise, and easy to understand. Avoid jargon.",
    },
  });
};

/**
 * Sends a message to the chat session.
 */
export const sendChatMessage = async (chat: Chat, message: string): Promise<string> => {
  try {
    const response: GenerateContentResponse = await chat.sendMessage({ message });
    return response.text || "I'm having trouble understanding that. Could you try asking in a different way?";
  } catch (error) {
    console.error("Chat error:", error);
    throw error;
  }
};

// --- Audio Helper Functions ---

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

