  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import React, { useState, useEffect, useRef } from 'react';
import { Chat } from '@google/genai';
import { createChatSession, sendChatMessage } from '../services/geminiService';
import { ChatMessage, SupportedLanguage } from '../types';

interface ChatInterfaceProps {
  language: SupportedLanguage;
  initialContext?: string;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ language, initialContext }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const [isListening, setIsListening] = useState(false);

  useEffect(() => {
    // Initialize chat session
    chatSessionRef.current = createChatSession(language, initialContext);

    // Initial greeting based on language
    const greetings = {
      [SupportedLanguage.ENGLISH]: "Hello! I am Noma, your farming advisor. How can I help your farm today?",
      [SupportedLanguage.HAUSA]: "Sannu! Ni ne Noma, mai ba ku shawara kan noma. Ta yaya zan taimake ku a gonar ku yau?",
      [SupportedLanguage.YORUBA]: "Pẹlẹ o! Emi ni Noma, oludamoran agbe rẹ. Bawo ni MO ṣe le ṣe iranlọwọ fun oko rẹ loni?",
