import { GoogleGenAI, Modality, Chat, GenerateContentResponse } from "@google/genai";
import { SupportedLanguage, DiagnosisResult, NutrientAnalysisResult } from "../types";

// Initialize the Gemini AI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Analyzes a crop image using Gemini Vision to detect diseases.
 */
export const analyzeCropImage = async (
  base64Image: string,
  language: SupportedLanguage
): Promise<DiagnosisResult> => {
  try {
    const prompt = `
      You are Noma, a patient and trusted Virtual Agronomic Advisor for smallholder farmers.
      Analyze the provided image of a crop.

      ROLE & IDENTITY:
      - You are a local extension officer, not a scientist.
      - Use simple words and farming examples.
      - Prioritize LOW COST and LOCALLY AVAILABLE solutions.
      - If uncertain, admit it and suggest taking a clearer photo.

      TASK:
      1. Identify the crop (Focus on African staples).
      2. Detect visible diseases, pests, or deficiencies.
      3. Provide ACTIONABLE ADVICE:
         - What to do today?
         - What to do this week?
         - Use step-by-step instructions ("First...", "Next...").
         - Suggest organic/home-made remedies first (e.g., Ash, Neem, Soap water) if effective.
      4. Safety: Warn about chemicals if suggested.

      IMPORTANT: Translate the ENTIRE output values into ${language}.

      Return ONLY a valid JSON object with this specific structure:
      {
        "crop": "Name of the crop",
        "status": "Healthy" or "Infected" or "Unknown",
        "diagnosis": "Simple name of the condition (e.g. 'Leaf Rust' not 'Puccinia sorghi')",
        "severity": "Low", "Medium", "High", or "None",
        "description": "Simple explanation in spoken style. e.g., 'The leaves have red spots like rust. This stops the plant from making food.'",
        "advice": {
          "organic": ["Step 1 (Low cost)", "Step 2"],
          "chemical": ["Step 1 (Only if necessary)", "Step 2"],
          "prevention": ["Simple tip 1", "Simple tip 2"]
        }
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image
            }
          },
          { text: prompt }
        ]
      },
      config: {
        temperature: 0.4,
      }
    });

    const text = response.text || "{}";
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleanText) as DiagnosisResult;

  } catch (error) {
    console.error("Analysis failed:", error);
    throw new Error("Failed to analyze the crop. Please try again.");
  }
};

