      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: prompt }
        ]
      },
      config: { temperature: 0.4 }
    });

    const text = response.text || "{}";
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleanText) as NutrientAnalysisResult;
  } catch (error) {
    console.error("Nutrient Analysis failed:", error);
    throw new Error("Failed to scan nutrients.");
  }
};

/**
 * Generates audio from text using Gemini TTS.
 */
export const generateSpeech = async (text: string, language: SupportedLanguage): Promise<AudioBuffer | null> => {
  try {
    const voiceName = 'Kore'; 

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: voiceName },
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      audioContext,
      24000,
      1
    );

    return audioBuffer;
  } catch (error) {
    console.error("TTS failed:", error);
    return null;
  }
};

/**
 * Creates a chat session for the Agri Advisor.
 */
export const createChatSession = (language: SupportedLanguage, context?: string): Chat => {
  const initialPrompt = context ? `Context regarding previous diagnosis: ${context}` : '';

  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `
        You are Noma, a Virtual Agronomic Advisor for smallholder farmers.

        LANGUAGE: Communicate in ${language} (or simple English if ${language} is English).

        IDENTITY:
        - You are a patient, trusted local extension officer.
        - You are NOT a scientist or salesperson.
        - You are respectful and encouraging.

        COMMUNICATION STYLE:
        - Use simple words and short sentences.
        - Behave like a real-time voice conversation.
        - Ask ONE question at a time.
        - Confirm understanding ("Is this clear?", "Should I explain more?").

        DECISION LOGIC:
        - Prioritize LOW COST and LOCALLY AVAILABLE solutions.
        - If a solution is expensive, offer a cheaper alternative.
        - Explain trade-offs (e.g., "This medicine works fast but costs money. Ash is free but takes longer.").

        TOPICS:
        - Crop disease, soil health, fertilizer (low cost first), weather, market timing.

