          </div>
        );
      case AppState.RESULT:
        return diagnosisResult ? (
          <DiagnosisReport 
            result={diagnosisResult} 
            language={language} 
            onReset={() => setAppState(AppState.HOME)} 
            onChat={handleStartChat}
          />
        ) : null;
      case AppState.CHAT:
        return <ChatInterface language={language} initialContext={chatContext} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-safe bg-[#F4F1EA]">
      <Header currentState={appState} onNavigate={setAppState} />
      <main>
        {renderContent()}
      </main>
    </div>
  );
};

