        "explanation": "Simple explanation",
        "options": {
          "A": { "type": "A", "title": "Title", "description": "Desc", "materials": [], "instructions": [], "duration": "" },
          "B": { "type": "B", "title": "Title", "description": "Desc", "materials": [], "instructions": [], "duration": "" },
          "C": { "type": "C", "title": "Title", "description": "Desc", "materials": [], "instructions": [], "duration": "" }
        }
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: fullPrompt }
        ]
      },
      config: { temperature: 0.4 }
    });

    const text = response.text || "{}";
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleanText) as NutrientAnalysisResult;
  } catch (error) {
    console.error("Nutrient Analysis failed:", error);
    throw new Error("Failed to scan nutrients.");
  }
};

/**
 * Analyzes Farm Input (Fertilizer/Pesticide) packaging.
 * Feature: Fake/Unsafe Alert + Dosage Calculator.
 */
export const analyzeFarmInput = async (
  base64Image: string,
  language: SupportedLanguage
): Promise<InputAnalysisResult> => {
  try {
    const prompt = `
      You are Noma. The user has scanned a farm input package (fertilizer, pesticide, or seed).

      TASK:
      1. Identify the product name and type.
      2. CHECK FOR AUTHENTICITY: Look for signs of fake products (typos, bad printing, missing seals). 
         If unsure, say "Cannot verify authenticity, please buy from trusted dealers."
         If it looks authentic, say "Packaging looks correct."
      3. SAFETY WARNING: Read the toxicity class or ingredients. Give a bold warning in ${language}.
      4. USAGE INSTRUCTIONS (LOCAL UNITS): 
         - Convert technical dosage (e.g. 50ml/20L) into "cups", "matchboxes", or "bottle caps" per "Knapsack sprayer" or "Bucket".

      IMPORTANT: Translate output to ${language}.

      Return ONLY JSON:
      {
        "productName": "Name",
        "isLikelyAuthentic": true/false,
        "safetyWarning": "Warning text...",
        "dosage": "e.g. Mix 2 matchboxes in one yellow jerrycan (20L).",
        "usage": "e.g. Spray in evening. Wear long sleeves."
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: prompt }
        ]
      },
      config: { temperature: 0.2 }
    });

    const text = response.text || "{}";
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleanText) as InputAnalysisResult;
  } catch (error) {
    console.error("Input Analysis failed:", error);
    throw new Error("Failed to analyze input.");
  }
};

/**
 * Generates audio from text using Gemini TTS.
 */
export const generateSpeech = async (text: string, language: SupportedLanguage): Promise<AudioBuffer | null> => {
  try {
    const voiceName = 'Kore'; 

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: voiceName },
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return null;

    const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      audioContext,
      24000,
      1
    );

    return audioBuffer;
  } catch (error) {
    console.error("TTS failed:", error);
    return null;
  }
};

