import React, { useState, useEffect, useRef } from 'react';
import { Chat } from '@google/genai';
import { createChatSession, sendChatMessage } from '../services/geminiService';
import { ChatMessage, SupportedLanguage } from '../types';

interface ChatInterfaceProps {
  language: SupportedLanguage;
  initialContext?: string;
}

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ language, initialContext }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const [isListening, setIsListening] = useState(false);

  useEffect(() => {
    // Initialize chat session
    chatSessionRef.current = createChatSession(language, initialContext);

    // Initial greeting based on language
    const greetings = {
      [SupportedLanguage.ENGLISH]: "Hello! I am Noma, your farming advisor. How can I help your farm today?",
      [SupportedLanguage.HAUSA]: "Sannu! Ni ne Noma, mai ba ku shawara kan noma. Ta yaya zan taimake ku a gonar ku yau?",
      [SupportedLanguage.YORUBA]: "Pẹlẹ o! Emi ni Noma, oludamoran agbe rẹ. Bawo ni MO ṣe le ṣe iranlọwọ fun oko rẹ loni?",
      [SupportedLanguage.IGBO]: "Nnọọ! Abụ m Noma, onye ndụmọdụ ọrụ ugbo gị. Kedu ka m ga-esi nyere gị aka n'ugbo gị taa?",
      [SupportedLanguage.SWAHILI]: "Hujambo! Mimi ni Noma, mshauri wako wa kilimo. Nawezaje kukusaidia shambani mwako leo?",
      [SupportedLanguage.ARABIC]: "مرحباً! أنا نعمة، مستشارك الزراعي. كيف يمكنني مساعدة مزرعتك اليوم؟",
      [SupportedLanguage.FRENCH]: "Bonjour! Je suis Noma, votre conseiller agricole. Comment puis-je vous aider aujourd'hui?"
    };

    setMessages([
      {
        id: '1',
        role: 'model',
        text: initialContext 
          ? (language === SupportedLanguage.ENGLISH ? "I see the report. Let's discuss what we can do about it. What questions do you have?" : "I see the report. Let's talk.") 
          : greetings[language] || greetings[SupportedLanguage.ENGLISH],
        timestamp: new Date()
      }
    ]);
  }, [language, initialContext]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    if (!inputText.trim() || !chatSessionRef.current) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsLoading(true);

    try {
      const responseText = await sendChatMessage(chatSessionRef.current, userMsg.text);
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "Network problem. Please say that again.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
    }
  };

  const startListening = () => {
    if ('webkitSpeechRecognition' in window) {
      const recognition = new (window as any).webkitSpeechRecognition();
      recognition.continuous = false;
      recognition.interimResults = false;

      let langCode = 'en-US';
      if (language === SupportedLanguage.FRENCH) langCode = 'fr-FR';
      else if (language === SupportedLanguage.ARABIC) langCode = 'ar-SA';
      else if (language === SupportedLanguage.SWAHILI) langCode = 'sw-KE';

      recognition.lang = langCode;

      recognition.onstart = () => setIsListening(true);
      recognition.onend = () => setIsListening(false);
      recognition.onresult = (event: any) => {
        const text = event.results[0][0].transcript;
        setInputText(text);
      };
      recognition.start();
    } else {
      alert("Voice input is not supported in this browser.");
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] max-w-md mx-auto bg-white/50 backdrop-blur-sm">
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-2xl px-5 py-3.5 shadow-sm text-[16px] leading-relaxed ${
                msg.role === 'user'
                  ? 'bg-gradient-to-br from-green-700 to-green-600 text-white rounded-br-sm'
                  : 'bg-white text-gray-800 border border-gray-100 rounded-bl-sm shadow-gray-200/50'
              }`}
            >
              <p className="whitespace-pre-wrap">{msg.text}</p>
              <span className={`text-[10px] block mt-1.5 font-medium ${msg.role === 'user' ? 'text-green-100/70' : 'text-gray-400'}`}>
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white rounded-2xl rounded-bl-sm px-5 py-4 border border-gray-100 shadow-sm">
              <div className="flex space-x-1.5">
                <div className="w-2 h-2 bg-gray-300 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-gray-300 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-gray-300 rounded-full animate-bounce delay-150"></div>
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-gray-100 pb-safe">
        <div className="flex gap-3 items-center bg-gray-50 p-2 rounded-[24px] border border-gray-200 focus-within:ring-2 focus-within:ring-green-500/20 focus-within:border-green-500 transition-all">
          <button 
            onClick={startListening}
            className={`p-3 rounded-full transition-all duration-300 ${
              isListening 
                ? 'bg-red-500 text-white shadow-md scale-110 animate-pulse' 
                : 'bg-white text-gray-500 shadow-sm hover:text-green-600'
            }`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </button>

          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask Noma..."
            className="flex-1 bg-transparent border-none focus:ring-0 text-gray-800 placeholder-gray-400 text-base py-2"
          />

          <button
            onClick={handleSend}
            disabled={isLoading || !inputText.trim()}
            className="p-3 rounded-full bg-green-700 text-white shadow-md disabled:opacity-50 disabled:shadow-none hover:bg-green-800 transition-colors"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useState } from 'react';

interface CameraCaptureProps {
  onCapture: (base64: string) => void;
}

export const CameraCapture: React.FC<CameraCaptureProps> = ({ onCapture }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [preview, setPreview] = useState<string | null>(null);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        setPreview(base64String);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleConfirm = () => {
    if (preview) {
      // Remove data URL prefix for API
      const base64Data = preview.split(',')[1];
      onCapture(base64Data);
    }
  };

  const handleRetake = () => {
    setPreview(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <div className="w-full max-w-md mx-auto p-5 flex flex-col items-center justify-center min-h-[70vh]">
      {!preview ? (
        <div 
            className="group w-full aspect-[3/4] max-h-[500px] border-3 border-dashed border-gray-300 rounded-[32px] flex flex-col items-center justify-center bg-white cursor-pointer hover:border-green-500 hover:bg-green-50/30 transition-all duration-300 shadow-sm"
            onClick={() => fileInputRef.current?.click()}
        >
          <div className="w-24 h-24 rounded-full bg-green-100 flex items-center justify-center mb-6 text-green-600 group-hover:scale-110 transition-transform duration-300 shadow-inner">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
            </svg>
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Take a Photo</h3>
          <p className="text-gray-500 font-medium text-center px-8">Tap here to open your camera and scan your crop</p>
          <input
            type="file"
            accept="image/*"
            capture="environment"
            ref={fileInputRef}
            className="hidden"
            onChange={handleFileChange}
          />
        </div>
      ) : (
        <div className="w-full flex flex-col items-center">
            <div className="relative w-full aspect-[3/4] max-h-[500px] rounded-[32px] overflow-hidden shadow-2xl mb-8 ring-4 ring-white">
                <img src={preview} alt="Crop Preview" className="w-full h-full object-cover" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent opacity-50"></div>
            </div>

            <div className="flex gap-4 w-full">
                <button 
                    onClick={handleRetake}
                    className="flex-1 py-4 px-6 rounded-2xl border-2 border-gray-200 text-gray-700 font-bold hover:bg-gray-50 transition-colors"
                >
                    Retake
                </button>
                <button 
                    onClick={handleConfirm}
                    className="flex-1 py-4 px-6 rounded-2xl bg-gradient-to-r from-green-700 to-green-600 text-white font-bold shadow-lg shadow-green-700/30 hover:shadow-xl hover:scale-[1.02] transition-all"
                >
                    Analyze Crop
                </button>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
