const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.HOME);
  const [language, setLanguage] = useState<SupportedLanguage>(SupportedLanguage.ENGLISH);
  const [diagnosisResult, setDiagnosisResult] = useState<DiagnosisResult | null>(null);
  const [chatContext, setChatContext] = useState<string | undefined>(undefined);

  const handleCapture = async (base64Image: string) => {
    setAppState(AppState.ANALYZING);
    try {
      const result = await analyzeCropImage(base64Image, language);
      setDiagnosisResult(result);
      setAppState(AppState.RESULT);
    } catch (error) {
      console.error(error);
      alert("Failed to analyze image. Please ensure you are connected to the internet.");
      setAppState(AppState.HOME);
    }
  };

  const handleStartChat = (context?: string) => {
    setChatContext(context);
    setAppState(AppState.CHAT);
  };

  const renderContent = () => {
    switch (appState) {
      case AppState.HOME:
        return (
          <LandingPage 
            language={language}
            setLanguage={setLanguage}
            onStartDiagnosis={() => setAppState(AppState.CAMERA)}
            onStartNutrient={() => setAppState(AppState.NUTRIENT_FLOW)}
            onStartChat={handleStartChat}
            onOpenCalculator={() => setAppState(AppState.CALCULATOR)}
          />
        );
      case AppState.NUTRIENT_FLOW:
        return <NutrientScanner language={language} onHome={() => setAppState(AppState.HOME)} />;
      case AppState.CALCULATOR:
        return <InputCalculator language={language} onBack={() => setAppState(AppState.HOME)} />;
      case AppState.CAMERA:
        return <CameraCapture onCapture={handleCapture} />;
      case AppState.ANALYZING:
        return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] px-4 text-center">
            <div className="relative">
                <div className="w-24 h-24 border-4 border-green-100 rounded-full"></div>
                <div className="w-24 h-24 border-4 border-green-600 border-t-transparent rounded-full animate-spin absolute top-0 left-0"></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-2xl">🌱</div>
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mt-6 mb-2">Analyzing Crop...</h2>
            <p className="text-gray-500 max-w-xs font-medium">Our AI Advisor is examining your crop for issues.</p>
          </div>
        );
      case AppState.RESULT:
        return diagnosisResult ? (
          <DiagnosisReport 
            result={diagnosisResult} 
            language={language} 
            onReset={() => setAppState(AppState.HOME)} 
            onChat={handleStartChat}
          />
        ) : null;
      case AppState.CHAT:
        return <ChatInterface language={language} initialContext={chatContext} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-[#FAFAF9] text-gray-900 font-sans selection:bg-green-100 selection:text-green-900">
      <div className="max-w-md mx-auto bg-white min-h-screen shadow-2xl shadow-gray-200/50">
        <Header currentState={appState} onNavigate={setAppState} />
        <main className="animate-fade-in">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

