import React, { useState, useRef, useEffect } from 'react';
import { SupportedLanguage, NutrientAnalysisResult, NutrientOption } from '../types';
import { analyzeNutrientDeficiency, generateSpeech } from '../services/geminiService';
import { CameraCapture } from './CameraCapture';

interface NutrientScannerProps {
  language: SupportedLanguage;
  onHome: () => void;
  onChat: (context?: string) => void;
}

type WizardStep = 'CONTEXT' | 'GUIDANCE' | 'CAMERA' | 'ANALYZING' | 'NEGOTIATION' | 'PLAN';

export const NutrientScanner: React.FC<NutrientScannerProps> = ({ language, onHome, onChat }) => {
  const [step, setStep] = useState<WizardStep>('CONTEXT');
  const [cropType, setCropType] = useState('');
  const [cropAge, setCropAge] = useState('');
  const [analysis, setAnalysis] = useState<NutrientAnalysisResult | null>(null);
  const [selectedOption, setSelectedOption] = useState<NutrientOption | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);

  // Auto-play audio guidance when entering specific steps
  useEffect(() => {
    const playGuidance = async () => {
      let text = "";
      if (step === 'GUIDANCE') {
        text = "Please take a clear picture of one leaf. Use a leaf from the middle of the plant. Make sure there is good daylight.";
      } else if (step === 'NEGOTIATION' && analysis) {
        text = `${analysis.explanation}. I found three ways to help. Which one can you do?`;
      }

      if (text) {
        const buffer = await generateSpeech(text, language);
        if (buffer) playAudio(buffer);
      }
    };
    playGuidance();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [step, analysis]);

  const playAudio = (buffer: AudioBuffer) => {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.onended = () => setIsPlaying(false);
    source.start(0);
    setIsPlaying(true);
  };

  const handleCapture = async (base64: string) => {
    setStep('ANALYZING');
    try {
      const result = await analyzeNutrientDeficiency(base64, cropType, cropAge, language);
      setAnalysis(result);
      setStep('NEGOTIATION');
    } catch (e) {
      alert("Something went wrong. Please try again.");
      setStep('CONTEXT');
    }
  };

  const renderContext = () => (
    <div className="max-w-md mx-auto p-6 bg-white rounded-2xl shadow-sm">
      <h2 className="text-2xl font-bold mb-4 text-brand-green">Tell me about your crop</h2>
      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Crop Type (Optional)</label>
          <input 
            type="text" 
            placeholder="e.g. Maize, Tomato" 
            className="w-full p-3 border border-gray-300 rounded-xl bg-gray-50"
            value={cropType}
            onChange={(e) => setCropType(e.target.value)}
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Crop Age (Optional)</label>
          <select 
            className="w-full p-3 border border-gray-300 rounded-xl bg-gray-50"
            value={cropAge}
            onChange={(e) => setCropAge(e.target.value)}
          >
            <option value="">I don't know</option>
            <option value="Just planted">Just planted (Seedling)</option>
            <option value="Growing">Growing (Vegetative)</option>
            <option value="Near harvest">Near harvest (Flowering/Fruiting)</option>
          </select>
        </div>
        <button 
          onClick={() => setStep('GUIDANCE')}
          className="w-full py-4 bg-brand-green text-white font-bold rounded-xl shadow-lg mt-4"
        >
          Next
        </button>
      </div>
    </div>
  );

  const renderGuidance = () => (
    <div className="max-w-md mx-auto p-6 bg-white rounded-2xl text-center">
      <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-4 text-brand-green">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
        </svg>
      </div>
      <h2 className="text-xl font-bold mb-4">Picture Tips</h2>
      <ul className="text-left space-y-3 mb-6 text-gray-700">
        <li className="flex gap-2">
            <span className="text-brand-green">✓</span> Use one leaf from the middle of the plant.
        </li>
        <li className="flex gap-2">
            <span className="text-brand-green">✓</span> Ensure good daylight (no flash).
        </li>
        <li className="flex gap-2">
            <span className="text-brand-green">✓</span> Hold phone steady.
        </li>
      </ul>
      <button 
        onClick={() => setStep('CAMERA')}
        className="w-full py-4 bg-brand-green text-white font-bold rounded-xl shadow-lg"
      >
        I am Ready
      </button>
    </div>
  );

  const renderNegotiation = () => {
    if (!analysis) return null;
    return (
      <div className="max-w-md mx-auto pb-20 p-4">
        <div className="bg-white p-4 rounded-2xl shadow-sm mb-6 border-l-4 border-brand-orange">
          <h2 className="text-xl font-bold text-gray-900 mb-2">{analysis.explanation}</h2>
          <p className="text-gray-600 text-sm italic">Note: This is an estimate, not a lab test.</p>
        </div>

        <h3 className="font-bold text-lg text-gray-800 mb-4">Which option can you do?</h3>

        <div className="space-y-4">
          {/* Option A */}
          <div 
            onClick={() => { setSelectedOption(analysis.options.A); setStep('PLAN'); }}
            className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 cursor-pointer hover:border-brand-green transition-all"
          >
            <div className="flex justify-between items-center mb-2">
               <span className="bg-green-100 text-brand-green px-2 py-1 rounded text-xs font-bold">Free / Local</span>
               <span className="text-xs text-gray-500">{analysis.options.A.duration}</span>
            </div>
            <h4 className="font-bold text-lg">{analysis.options.A.title}</h4>
            <p className="text-gray-600 text-sm">{analysis.options.A.description}</p>
          </div>

          {/* Option B */}
          <div 
            onClick={() => { setSelectedOption(analysis.options.B); setStep('PLAN'); }}
            className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 cursor-pointer hover:border-brand-green transition-all"
          >
            <div className="flex justify-between items-center mb-2">
               <span className="bg-blue-100 text-blue-800 px-2 py-1 rounded text-xs font-bold">Low Cost</span>
               <span className="text-xs text-gray-500">{analysis.options.B.duration}</span>
            </div>
            <h4 className="font-bold text-lg">{analysis.options.B.title}</h4>
            <p className="text-gray-600 text-sm">{analysis.options.B.description}</p>
          </div>

          {/* Option C */}
          <div 
            onClick={() => { setSelectedOption(analysis.options.C); setStep('PLAN'); }}
            className="bg-white p-4 rounded-xl shadow-sm border border-gray-200 cursor-pointer hover:border-brand-green transition-all"
          >
            <div className="flex justify-between items-center mb-2">
               <span className="bg-purple-100 text-purple-800 px-2 py-1 rounded text-xs font-bold">Best Practice</span>
               <span className="text-xs text-gray-500">{analysis.options.C.duration}</span>
            </div>
            <h4 className="font-bold text-lg">{analysis.options.C.title}</h4>
            <p className="text-gray-600 text-sm">{analysis.options.C.description}</p>
          </div>
        </div>
      </div>
    );
  };

  const renderPlan = () => {
    if (!selectedOption) return null;
    return (
        <div className="max-w-md mx-auto p-4 pb-20">
            <div className="bg-white rounded-2xl shadow-lg overflow-hidden mb-6">
                <div className="bg-brand-green p-4 text-white">
                    <h2 className="text-xl font-bold">Your Action Plan</h2>
                    <p className="opacity-90 text-sm">{selectedOption.title}</p>
                </div>
                <div className="p-6">
                    <h3 className="font-bold text-gray-900 mb-2">Materials Needed:</h3>
                    <div className="flex flex-wrap gap-2 mb-6">
                        {selectedOption.materials.map((m, i) => (
                            <span key={i} className="bg-gray-100 px-3 py-1 rounded-full text-sm font-medium text-gray-700">{m}</span>
                        ))}
                    </div>

                    <h3 className="font-bold text-gray-900 mb-3">Instructions:</h3>
                    <div className="space-y-4">
                        {selectedOption.instructions.map((inst, i) => (
                            <div key={i} className="flex gap-3">
                                <div className="w-6 h-6 rounded-full bg-brand-orange text-white flex items-center justify-center font-bold text-sm shrink-0">
                                    {i + 1}
                                </div>
                                <p className="text-gray-700">{inst}</p>
                            </div>
                        ))}
                    </div>

                    <div className="mt-6 p-4 bg-blue-50 rounded-xl text-blue-800 text-sm font-medium flex items-center gap-2">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                        {selectedOption.duration}
                    </div>
                </div>
            </div>

            <button 
                onClick={() => onChat(`I have a plan for nutrient deficiency using ${selectedOption.title}. I have questions about how to apply it.`)}
                className="w-full py-4 bg-white border-2 border-brand-green text-brand-green font-bold rounded-xl mb-4 flex items-center justify-center gap-2 hover:bg-green-50"
            >
                 <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M18 10c0 3.866-3.582 7-8 7a8.841 8.841 0 01-4.083-.98L2 17l1.338-3.123C2.493 12.767 2 11.434 2 10c0-3.866 3.582-7 8-7s8 3.134 8 7zM7 9H5v2h2V9zm8 0h-2v2h2V9zM9 9h2v2H9V9z" clipRule="evenodd" />
                </svg>
                Talk to Advisor
            </button>

            <button 
                onClick={onHome}
                className="w-full py-4 bg-brand-green text-white font-bold rounded-xl mb-4"
            >
                Done
            </button>

            <button 
                className="w-full py-4 bg-gray-900 text-white font-bold rounded-xl shadow-lg flex items-center justify-center gap-2"
                onClick={() => alert("Reminder set! I will notify you in 7 days.")}
            >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" /></svg>
                Remind Me in 7 Days
            </button>
        </div>
    );
  };

  return (
    <div className="min-h-[80vh]">
      {step === 'CONTEXT' && renderContext()}
      {step === 'GUIDANCE' && renderGuidance()}
      {step === 'CAMERA' && <CameraCapture onCapture={handleCapture} />}
      {step === 'ANALYZING' && (
        <div className="flex flex-col items-center justify-center h-[60vh] text-center px-4">
           <div className="w-16 h-16 border-4 border-brand-green border-t-transparent rounded-full animate-spin mb-4"></div>
           <h2 className="text-xl font-bold">Scanning Leaves...</h2>
           <p className="text-gray-500">Checking for Nitrogen, Phosphorus, and Potassium.</p>
        </div>
      )}
      {step === 'NEGOTIATION' && renderNegotiation()}
      {step === 'PLAN' && renderPlan()}
    </div>
  );
};

