  const [isLoading, setIsLoading] = useState(false);
  const [errorState, setErrorState] = useState<string | null>(null);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const [isListening, setIsListening] = useState(false);

  useEffect(() => {
    // Initialize chat session
    try {
      chatSessionRef.current = createChatSession(language, initialContext);
      setErrorState(null);
    } catch (e) {
      setErrorState("Failed to start chat session. Please refresh.");
    }

    // Initial greeting based on language
    const greetings = {
      [SupportedLanguage.ENGLISH]: "Hello! I am Noma, your farming advisor. How can I help your farm today?",
      [SupportedLanguage.HAUSA]: "Sannu! Ni ne Noma, mai ba ku shawara kan noma. Ta yaya zan taimake ku a gonar ku yau?",
      [SupportedLanguage.YORUBA]: "Pẹlẹ o! Emi ni Noma, oludamoran agbe rẹ. Bawo ni MO ṣe le ṣe iranlọwọ fun oko rẹ loni?",
      [SupportedLanguage.IGBO]: "Nnọọ! Abụ m Noma, onye ndụmọdụ ọrụ ugbo gị. Kedu ka m ga-esi nyere gị aka n'ugbo gị taa?",
      [SupportedLanguage.SWAHILI]: "Hujambo! Mimi ni Noma, mshauri wako wa kilimo. Nawezaje kukusaidia shambani mwako leo?",
      [SupportedLanguage.ARABIC]: "مرحباً! أنا نعمة، مستشارك الزراعي. كيف يمكنني مساعدة مزرعتك اليوم؟",
      [SupportedLanguage.FRENCH]: "Bonjour! Je suis Noma, votre conseiller agricole. Comment puis-je vous aider aujourd'hui?"
    };

    setMessages([
      {
        id: '1',
        role: 'model',
        text: initialContext 
          ? (language === SupportedLanguage.ENGLISH ? "I see the report. Let's discuss what we can do about it. What questions do you have?" : "I see the report. Let's talk.") 
          : greetings[language] || greetings[SupportedLanguage.ENGLISH],
        timestamp: new Date()
      }
    ]);

    // Auto-focus on mount
    inputRef.current?.focus();
  }, [language, initialContext]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    const trimmedInput = inputText.trim();
    if (!trimmedInput || isLoading || !chatSessionRef.current) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: trimmedInput,
      timestamp: new Date()
    };

    // Optimistically add user message and clear input
    setMessages(prev => [...prev, userMsg]);
    const previousInput = inputText;
    setInputText('');
    setIsLoading(true);
    setErrorState(null);

    try {
      const responseText = await sendChatMessage(chatSessionRef.current, userMsg.text);
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error("Chat Error:", error);
      // Restore the input so the user doesn't lose their message
      setInputText(previousInput);

      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "I'm sorry, I lost connection for a moment. Please check your internet and try sending that again.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
      setErrorState("Connection problem. Your message was not sent.");
    } finally {
      setIsLoading(false);
      // Focus back for next message
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  };

  const startListening = () => {
    if ('webkitSpeechRecognition' in window) {
      const recognition = new (window as any).webkitSpeechRecognition();
      recognition.continuous = false;
      recognition.interimResults = false;

      let langCode = 'en-US';
      if (language === SupportedLanguage.FRENCH) langCode = 'fr-FR';
      else if (language === SupportedLanguage.ARABIC) langCode = 'ar-SA';
      else if (language === SupportedLanguage.SWAHILI) langCode = 'sw-KE';

      recognition.lang = langCode;

      recognition.onstart = () => setIsListening(true);
      recognition.onend = () => setIsListening(false);
      recognition.onresult = (event: any) => {
        const text = event.results[0][0].transcript;
        if (text) {
           setInputText(text);
           // Optional: auto-send if you prefer
        }
      };
      recognition.onerror = () => setIsListening(false);
      recognition.start();
    } else {
      alert("Voice input is not supported in this browser.");
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] max-w-md mx-auto bg-white/50 backdrop-blur-sm">
      <div className="flex-1 overflow-y-auto p-4 space-y-6 scroll-smooth no-scrollbar">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in`}
          >
            <div
              className={`relative max-w-[85%] rounded-2xl px-5 py-3.5 shadow-sm text-[16px] leading-relaxed transition-all ${
                msg.role === 'user'
                  ? 'bg-gradient-to-br from-green-700 to-green-600 text-white rounded-br-sm'
                  : 'bg-white text-gray-800 border border-gray-100 rounded-bl-sm shadow-gray-200/50'
              }`}
            >
              <p className="whitespace-pre-wrap break-words">{msg.text}</p>
              <span className={`text-[10px] block mt-1.5 font-medium ${msg.role === 'user' ? 'text-green-100/70' : 'text-gray-400'}`}>
                {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-white rounded-2xl rounded-bl-sm px-5 py-4 border border-gray-100 shadow-sm">
              <div className="flex space-x-1.5">
                <div className="w-2 h-2 bg-green-500/40 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-green-500/40 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-green-500/40 rounded-full animate-bounce delay-150"></div>
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-4 bg-white border-t border-gray-100 pb-safe">
        {errorState && (
          <div className="mb-3 px-4 py-2 bg-red-50 text-red-600 text-xs rounded-xl border border-red-100 animate-in fade-in slide-in-from-bottom-2">
            {errorState}
          </div>
        )}

        <div className="flex gap-3 items-center bg-gray-50 p-2 rounded-[24px] border border-gray-200 focus-within:ring-2 focus-within:ring-green-500/20 focus-within:border-green-500 transition-all relative">
          <button 
            onClick={startListening}
            title="Voice Input"
            className={`p-3 rounded-full transition-all duration-300 ${
              isListening 
                ? 'bg-red-500 text-white shadow-md scale-110 animate-pulse' 
                : 'bg-white text-gray-500 shadow-sm hover:text-green-600 active:scale-95'
            }`}
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            </svg>
          </button>

          <div className="flex-1 relative flex items-center">
            <input
              ref={inputRef}
              type="text"
              value={inputText}
              maxLength={MAX_CHARS}
              onChange={(e) => {
                setInputText(e.target.value);
                if (errorState) setErrorState(null);
              }}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask Noma..."
              className="w-full bg-transparent border-none focus:ring-0 text-gray-800 placeholder-gray-400 text-base py-2 pr-10"
              disabled={isLoading}
            />
            {inputText.length > 0 && (
              <span className={`absolute right-0 text-[10px] font-bold ${inputText.length > MAX_CHARS * 0.9 ? 'text-red-500' : 'text-gray-300'}`}>
                {inputText.length}/{MAX_CHARS}
              </span>
            )}
          </div>

          <button
            onClick={handleSend}
            disabled={isLoading || !inputText.trim()}
            className="p-3 rounded-full bg-green-700 text-white shadow-md disabled:bg-gray-200 disabled:text-gray-400 disabled:shadow-none hover:bg-green-800 active:scale-95 transition-all"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
              <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Chat } from '@google/genai';
import { createChatSession, sendChatMessage } from '../services/geminiService';
import { ChatMessage, SupportedLanguage } from '../types';

interface ChatInterfaceProps {
  language: SupportedLanguage;
  initialContext?: string;
}

const MAX_CHARS = 1000;

export const ChatInterface: React.FC<ChatInterfaceProps> = ({ language, initialContext }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [errorState, setErrorState] = useState<string | null>(null);
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const [isListening, setIsListening] = useState(false);

  useEffect(() => {
    const initChat = () => {
      try {
        chatSessionRef.current = createChatSession(language, initialContext);
        setErrorState(null);
      } catch (e) {
        setErrorState("Could not start Noma Advisor. Please refresh the page.");
      }
    };

    initChat();

    // Initial greeting
    const greetings = {
      [SupportedLanguage.ENGLISH]: "Hello! I am Noma, your farming advisor. How can I help your farm today?",
      [SupportedLanguage.HAUSA]: "Sannu! Ni ne Noma, mai ba ku shawara kan noma. Ta yaya zan taimake ku a gonar ku yau?",
      [SupportedLanguage.YORUBA]: "Pẹlẹ o! Emi ni Noma, oludamoran agbe rẹ. Bawo ni MO ṣe le ṣe iranlọwọ fun oko rẹ loni?",
      [SupportedLanguage.IGBO]: "Nnọọ! Abụ m Noma, onye ndụmọdụ ọrụ ugbo gị. Kedu ka m ga-esi nyere gị aka n'ugbo gị taa?",
      [SupportedLanguage.SWAHILI]: "Hujambo! Mimi ni Noma, mshauri wako wa kilimo. Nawezaje kukusaidia shambani mwako leo?",
      [SupportedLanguage.ARABIC]: "مرحباً! أنا نعمة، مستشارك الزراعي. كيف يمكنني مساعدة مزرعتك اليوم؟",
      [SupportedLanguage.FRENCH]: "Bonjour! Je suis Noma, votre conseiller agricole. Comment puis-je vous aider aujourd'hui?"
    };

    setMessages([
      {
        id: '1',
        role: 'model',
        text: initialContext 
          ? (language === SupportedLanguage.ENGLISH ? "I see the report. Let's discuss what we can do about it. What questions do you have?" : "I see the report. Let's talk.") 
          : greetings[language] || greetings[SupportedLanguage.ENGLISH],
        timestamp: new Date()
      }
    ]);

    inputRef.current?.focus();
  }, [language, initialContext]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    const trimmedInput = inputText.trim();

    // 1. Basic Validation
    if (!trimmedInput) return;
    if (isLoading) return;

    // 2. Offline Check
    if (!navigator.onLine) {
      setErrorState("You are currently offline. Please check your internet connection and try again.");
      return;
    }

    // 3. Session Check
    if (!chatSessionRef.current) {
      setErrorState("Advisor session lost. Re-connecting...");
      try {
        chatSessionRef.current = createChatSession(language, initialContext);
      } catch (e) {
        setErrorState("Connection failed. Please refresh.");
        return;
      }
    }

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: trimmedInput,
      timestamp: new Date()
    };

    // Optimistic Update
    setMessages(prev => [...prev, userMsg]);
    const previousInput = inputText;
    setInputText('');
    setIsLoading(true);
    setErrorState(null);

    try {
      const responseText = await sendChatMessage(chatSessionRef.current, userMsg.text);
      const modelMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, modelMsg]);
    } catch (error) {
      console.error("Chat Error:", error);

      // Restore input on failure
      setInputText(previousInput);
      setErrorState("Failed to send message. Please check your signal and try again.");

      const errorMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: "I'm sorry, I couldn't receive your message. It might be a bad signal. I've kept your text in the box so you can try sending it again.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsLoading(false);
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  };

  const startListening = () => {
    if (!('webkitSpeechRecognition' in window)) {
      alert("Voice input is not supported in this browser.");
      return;
    }

    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.continuous = false;
    recognition.interimResults = false;

    let langCode = 'en-US';
    if (language === SupportedLanguage.FRENCH) langCode = 'fr-FR';
    else if (language === SupportedLanguage.ARABIC) langCode = 'ar-SA';
    else if (language === SupportedLanguage.SWAHILI) langCode = 'sw-KE';

    recognition.lang = langCode;

    recognition.onstart = () => {
      setIsListening(true);
      setErrorState(null);
    };
    recognition.onend = () => setIsListening(false);
    recognition.onresult = (event: any) => {
      const text = event.results[0][0].transcript;
      if (text) {
        setInputText(text);
      }
    };
    recognition.onerror = (event: any) => {
      setIsListening(false);
      if (event.error === 'network') {
        setErrorState("Voice input needs internet. Check your connection.");
      }
    };
    recognition.start();
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] max-w-md mx-auto bg-[#FAFAF9]">
      {/* Message List */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar">
