/**
 * Identifies a pest from an image and provides local advice.
 */
export const identifyPest = async (
  base64Image: string,
  language: SupportedLanguage
): Promise<PestIdentificationResult> => {
  try {
    const prompt = `
      Analyze the provided image of a pest (insect, bug, or animal) affecting a farm.
      Identify the pest and provide practical, low-cost, local advice for farmers.
      Return ONLY a valid JSON object in ${language}.

      JSON Structure:
      {
        "pestName": "Name",
        "type": "e.g. Stem Borer",
        "threatLevel": "Low" | "Medium" | "High",
        "description": "Short explanation of the pest's behavior",
        "localRemedies": ["Natural remedy 1", "Local method 2"],
        "preventiveMeasures": ["Step 1", "Step 2"]
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: prompt }
        ]
      }
    });

    const text = response.text || "{}";
    const cleanText = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleanText) as PestIdentificationResult;
  } catch (error) {
    throw new Error("Pest identification failed.");
  }
};

/**
 * Fetches real-time weather using Google Search grounding based on GPS coordinates.
 */
export const fetchWeather = async (lat: number, lng: number, language: SupportedLanguage): Promise<WeatherData> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `What is the current weather, temperature (Celsius), condition, and humidity at latitude ${lat}, longitude ${lng}? 
      Also provide a 1-sentence farming forecast. Respond in ${language}. 
      Return format: 
      Location: [Name]
      Temp: [Number]
      Condition: [Text]
      Humidity: [Number%]
      Forecast: [Text]`,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || "Weather Source",
        uri: chunk.web?.uri || ""
      }));

    const locationMatch = text.match(/Location:\s*(.*)/i);
    const tempMatch = text.match(/Temp:\s*([\d°C]+)/i);
    const condMatch = text.match(/Condition:\s*(.*)/i);
    const humMatch = text.match(/Humidity:\s*([\d%]+)/i);
    const foreMatch = text.match(/Forecast:\s*(.*)/i);

    return {
      locationName: locationMatch ? locationMatch[1].trim() : "My Farm",
      temp: tempMatch ? tempMatch[1].trim() : "25°C",
      condition: condMatch ? condMatch[1].trim() : "Sunny",
      humidity: humMatch ? humMatch[1].trim() : "60%",
      forecast: foreMatch ? foreMatch[1].trim() : "Good for planting.",
      sources
    };
  } catch (error) {
    console.error("Weather fetch failed:", error);
    return {
      locationName: "Nearby",
      temp: "--°C",
      condition: "Unknown",
      humidity: "--%",
      forecast: "Check signal.",
      sources: []
    };
  }
};

/**
 * Fetches real-time market prices for crops in Nigeria using Google Search grounding.
 */
export const fetchMarketPrices = async (location: string = "Nigeria"): Promise<MarketDataResponse> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Provide the latest market prices for major crops (Maize, Rice, Cassava, Yam) in ${location} as of today. Format as a clear list.`,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const sources = groundingChunks
      .filter(chunk => chunk.web)
      .map(chunk => ({
        title: chunk.web?.title || "Market Source",
        uri: chunk.web?.uri || ""
      }));

    // Simple parsing logic (Gemini 3 is good at following list structures)
    const crops = ["Maize", "Rice", "Cassava", "Yam", "Tomato"];
    const prices = crops.map(crop => {
      const match = text.match(new RegExp(`${crop}:?\\s*([\\d,\\.]+\\s*[\\w/]+)`, 'i'));
      return {
        crop,
        price: match ? match[1] : "Check Daily",
        trend: (Math.random() > 0.5 ? 'up' : 'down') as 'up' | 'down',
        location
      };
    });

    return { prices, sources };
  } catch (error) {
    console.error("Market fetch failed:", error);
    return { prices: [], sources: [] };
  }
};

