import React, { useState, useEffect } from 'react';
import { PestIdentificationResult, SupportedLanguage } from '../types';
import { generateSpeech } from '../services/geminiService';

interface PestReportProps {
  result: PestIdentificationResult;
  language: SupportedLanguage;
  onReset: () => void;
  onChat: (context: string) => void;
}

export const PestReport: React.FC<PestReportProps> = ({ result, language, onReset, onChat }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [audioBuffer, setAudioBuffer] = useState<AudioBuffer | null>(null);
  const [isLoadingAudio, setIsLoadingAudio] = useState(false);

  useEffect(() => {
    const loadAudio = async () => {
      setIsLoadingAudio(true);
      const textToRead = `${result.pestName}. It is a ${result.type}. ${result.description}. Threat level is ${result.threatLevel}.`;
      const buffer = await generateSpeech(textToRead, language);
      setAudioBuffer(buffer);
      setIsLoadingAudio(false);
    };
    loadAudio();
  }, [result, language]);

  const playAudio = () => {
    if (!audioBuffer) return;
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({sampleRate: 24000});
    const source = ctx.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(ctx.destination);
    source.onended = () => setIsPlaying(false);
    source.start(0);
    setIsPlaying(true);
  };

  const threatColor = {
    'Low': 'bg-green-100 text-green-800',
    'Medium': 'bg-orange-100 text-orange-800',
    'High': 'bg-red-100 text-red-800'
  }[result.threatLevel] || 'bg-gray-100 text-gray-800';

  return (
    <div className="max-w-md mx-auto p-4 pb-20">
      <div className="bg-brand-orange text-white p-4 rounded-2xl shadow-lg mb-6 flex items-center justify-between">
        <div>
          <h3 className="font-semibold text-sm opacity-90">Listen to Identification</h3>
          <p className="text-xs opacity-75">{language}</p>
        </div>
        <button 
          onClick={playAudio}
          disabled={isLoadingAudio || !audioBuffer}
          className="w-12 h-12 rounded-full bg-white/20 flex items-center justify-center hover:bg-white/30 transition disabled:opacity-50"
        >
          {isLoadingAudio ? '...' : isPlaying ? '■' : '▶'}
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden mb-6">
        <div className="p-5">
          <div className="flex justify-between items-start mb-2">
            <div>
              <p className="text-sm text-gray-500 uppercase font-semibold tracking-wider">{result.type}</p>
              <h2 className="text-2xl font-bold text-gray-900">{result.pestName}</h2>
            </div>
            <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide ${threatColor}`}>
              {result.threatLevel} Threat
            </span>
          </div>
          <p className="text-gray-700 leading-relaxed mt-2">{result.description}</p>
        </div>
      </div>

      <div className="space-y-4">
        <div className="bg-white p-5 rounded-2xl shadow-sm border border-l-4 border-l-brand-orange border-gray-100">
          <h4 className="font-bold text-gray-900 mb-3 flex items-center gap-2">
            🌿 Local Remedies
          </h4>
          <ul className="space-y-2">
            {result.localRemedies.map((r, i) => (
              <li key={i} className="flex gap-3 text-gray-700 text-sm">
                <span className="font-bold text-brand-orange">•</span>
                <span>{r}</span>
              </li>
            ))}
          </ul>
        </div>

        <div className="bg-white p-5 rounded-2xl shadow-sm border border-l-4 border-l-brand-green border-gray-100">
          <h4 className="font-bold text-gray-900 mb-3 flex items-center gap-2">
            🛡️ Prevention
          </h4>
          <ul className="space-y-2">
            {result.preventiveMeasures.map((m, i) => (
              <li key={i} className="flex gap-3 text-gray-700 text-sm">
                <span className="font-bold text-brand-green">•</span>
                <span>{m}</span>
              </li>
            ))}
          </ul>
        </div>
      </div>

      <div className="flex gap-4 mt-8">
        <button onClick={onReset} className="flex-1 py-3.5 border-2 border-gray-200 text-gray-700 rounded-xl font-bold">
          Back Home
        </button>
        <button onClick={() => onChat(`I found a ${result.pestName} on my farm. Can you tell me more about its control?`)} className="flex-1 py-3.5 bg-brand-orange text-white rounded-xl font-bold">
          Ask Advisor
        </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AppState, SupportedLanguage, DiagnosisResult, PestIdentificationResult } from './types';
import { Header } from './components/Header';
import { CameraCapture } from './components/CameraCapture';
import { DiagnosisReport } from './components/DiagnosisReport';
import { PestReport } from './components/PestReport';
import { analyzeCropImage, identifyPest } from './services/geminiService';
import { LandingPage } from './components/LandingPage';
import { ChatInterface } from './components/ChatInterface';
import { NutrientScanner } from './components/NutrientScanner';
import { InputCalculator } from './components/InputCalculator';
import { LiveTalk } from './components/LiveTalk';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.HOME);
  const [language, setLanguage] = useState<SupportedLanguage>(SupportedLanguage.ENGLISH);
  const [diagnosisResult, setDiagnosisResult] = useState<DiagnosisResult | null>(null);
  const [pestResult, setPestResult] = useState<PestIdentificationResult | null>(null);
  const [chatContext, setChatContext] = useState<string | undefined>(undefined);

  const handleCapture = async (base64Image: string) => {
    // Determine which analysis to perform based on appState
    if (appState === AppState.PEST_SCAN) {
      setAppState(AppState.ANALYZING);
      try {
        const result = await identifyPest(base64Image, language);
        setPestResult(result);
        setAppState(AppState.PEST_RESULT);
      } catch (error) {
        alert("Failed to identify pest.");
        setAppState(AppState.HOME);
      }
    } else {
      setAppState(AppState.ANALYZING);
      try {
        const result = await analyzeCropImage(base64Image, language);
        setDiagnosisResult(result);
        setAppState(AppState.RESULT);
      } catch (error) {
        console.error(error);
        alert("Failed to analyze image.");
        setAppState(AppState.HOME);
      }
    }
  };

  const handleStartChat = (context?: string) => {
    setChatContext(context);
    setAppState(AppState.CHAT);
  };

  const renderContent = () => {
    switch (appState) {
      case AppState.HOME:
        return (
          <LandingPage 
            language={language}
            setLanguage={setLanguage}
            onStartDiagnosis={() => setAppState(AppState.CAMERA)}
            onStartPest={() => setAppState(AppState.PEST_SCAN)}
            onStartNutrient={() => setAppState(AppState.NUTRIENT_FLOW)}
            onStartChat={handleStartChat}
            onStartLive={() => setAppState(AppState.LIVE_TALK)}
            onOpenCalculator={() => setAppState(AppState.CALCULATOR)}
          />
        );
      case AppState.LIVE_TALK:
        return <LiveTalk language={language} onEnd={() => setAppState(AppState.HOME)} />;
      case AppState.NUTRIENT_FLOW:
        return (
          <NutrientScanner 
            language={language} 
            onHome={() => setAppState(AppState.HOME)} 
            onChat={handleStartChat} 
          />
        );
      case AppState.CALCULATOR:
        return <InputCalculator language={language} onBack={() => setAppState(AppState.HOME)} />;
      case AppState.CAMERA:
      case AppState.PEST_SCAN:
        return <CameraCapture onCapture={handleCapture} />;
      case AppState.ANALYZING:
        return (
          <div className="flex flex-col items-center justify-center min-h-[60vh] px-4 text-center">
            <div className="relative">
                <div className="w-24 h-24 border-4 border-green-100 rounded-full"></div>
                <div className="w-24 h-24 border-4 border-green-600 border-t-transparent rounded-full animate-spin absolute top-0 left-0"></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-2xl">🌱</div>
            </div>
            <h2 className="text-2xl font-bold text-gray-900 mt-6 mb-2">Analyzing...</h2>
            <p className="text-gray-500 max-w-xs font-medium">Noma is looking into it.</p>
          </div>
        );
      case AppState.RESULT:
        return diagnosisResult ? (
          <DiagnosisReport 
            result={diagnosisResult} 
            language={language} 
            onReset={() => setAppState(AppState.HOME)} 
            onChat={handleStartChat}
          />
        ) : null;
      case AppState.PEST_RESULT:
        return pestResult ? (
          <PestReport 
            result={pestResult} 
            language={language} 
            onReset={() => setAppState(AppState.HOME)} 
            onChat={handleStartChat}
          />
        ) : null;
      case AppState.CHAT:
        return <ChatInterface language={language} initialContext={chatContext} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-[#FAFAF9] text-gray-900 font-sans selection:bg-green-100 selection:text-green-900">
      <div className="max-w-md mx-auto bg-white min-h-screen shadow-2xl shadow-gray-200/50">
        <Header currentState={appState} onNavigate={setAppState} />
        <main className="animate-fade-in">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Modality, Chat, GenerateContentResponse, Type } from "@google/genai";
import { SupportedLanguage, DiagnosisResult, NutrientAnalysisResult, InputAnalysisResult, MarketDataResponse, WeatherData, PestIdentificationResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Identifies a pest from an image and provides local advice.
 */
export const identifyPest = async (
  base64Image: string,
  language: SupportedLanguage
): Promise<PestIdentificationResult> => {
  try {
    const prompt = `
      Analyze the provided image of a pest (insect, bug, or animal) affecting a farm.
      Identify the pest and provide practical, low-cost, local advice for farmers.
      Return ONLY a valid JSON object in ${language}.

      JSON Structure:
      {
        "pestName": "Name",
        "type": "e.g. Stem Borer",
        "threatLevel": "Low" | "Medium" | "High",
        "description": "Short explanation of the pest's behavior",
        "localRemedies": ["Natural remedy 1", "Local method 2"],
        "preventiveMeasures": ["Step 1", "Step 2"]
      }
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
          { text: prompt }
        ]
      }
    });

    const text = response.text || "{}";
