function decode(b: string) {
  const s = atob(b);
  const bt = new Uint8Array(s.length);
  for (let i = 0; i < s.length; i++) bt[i] = s.charCodeAt(i);
  return bt;
}
async function decodeAudioData(d: Uint8Array, ctx: AudioContext, r: number, c: number) {
  const i16 = new Int16Array(d.buffer);
  const b = ctx.createBuffer(c, i16.length, r);
  const cd = b.getChannelData(0);
  for (let i = 0; i < i16.length; i++) cd[i] = i16[i] / 32768.0;
  return b;
}

import React, { useState, useEffect } from 'react';
import { SupportedLanguage, FarmMappingResult } from '../types';
import { mapFarmLocation } from '../services/geminiService';

interface FarmMapperProps {
  language: SupportedLanguage;
  onHome: () => void;
  onSetSize: (area: number) => void;
}

export const FarmMapper: React.FC<FarmMapperProps> = ({ language, onHome, onSetSize }) => {
  const [mapping, setMapping] = useState<FarmMappingResult | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [dimensions, setDimensions] = useState({ length: 0, width: 0 });
  const [coords, setCoords] = useState<{lat: number, lng: number} | null>(null);

  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (pos) => {
        const { latitude, longitude } = pos.coords;
        setCoords({ lat: latitude, lng: longitude });
        const result = await mapFarmLocation(latitude, longitude, language);
        setMapping(result);
        setIsLoading(false);
      }, () => setIsLoading(false));
    } else {
      setIsLoading(false);
    }
  }, [language]);

  const calculateArea = () => {
    const area = dimensions.length * dimensions.width;
    onSetSize(area);
    alert(`Farm size set to ${area} sqm. This will update your fertilizer calculations!`);
    onHome();
  };

  return (
    <div className="max-w-md mx-auto p-4 pb-20">
      <div className="bg-white rounded-[32px] overflow-hidden shadow-xl border border-gray-100 mb-6">
        <div className="h-48 bg-gray-100 relative overflow-hidden flex items-center justify-center">
