                </div>
                <p className="text-sm font-black text-gray-900 bg-white/80 backdrop-blur-sm px-3 py-1 rounded-full border border-white">
                   {coords.lat.toFixed(4)}, {coords.lng.toFixed(4)}
                </p>
             </div>
          ) : (
            <p className="text-gray-500 font-bold">Location access required</p>
          )}
        </div>

        <div className="p-6">
           <h3 className="font-black text-gray-900 text-lg mb-2">Farm Location Detail</h3>
           <p className="text-sm text-gray-600 leading-relaxed mb-4">
