              ))}
           </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-gray-100 mb-8">
         <h3 className="font-black text-gray-900 text-xs uppercase tracking-widest mb-4">Size Your Land (Meters)</h3>
         <div className="grid grid-cols-2 gap-4">
            <div>
               <label className="text-[10px] font-black text-gray-400 uppercase mb-1 block">Length</label>
               <input 
                  type="number" 
                  className="w-full bg-gray-50 border border-gray-200 rounded-2xl p-4 font-black" 
                  placeholder="0"
                  onChange={(e) => setDimensions({...dimensions, length: Number(e.target.value)})}
               />
            </div>
            <div>
               <label className="text-[10px] font-black text-gray-400 uppercase mb-1 block">Width</label>
               <input 
                  type="number" 
                  className="w-full bg-gray-50 border border-gray-200 rounded-2xl p-4 font-black" 
                  placeholder="0"
                  onChange={(e) => setDimensions({...dimensions, width: Number(e.target.value)})}
