         </div>
         <div className="mt-4 p-4 bg-orange-50 rounded-2xl flex justify-between items-center border border-orange-100">
            <span className="text-xs font-black text-orange-800 uppercase">Estimated Area</span>
            <span className="text-lg font-black text-brand-orange">{dimensions.length * dimensions.width} sqm</span>
         </div>
         <button 
            onClick={calculateArea}
            className="w-full mt-4 py-4 bg-brand-green text-white font-black rounded-2xl shadow-lg transition-all active:scale-95"
         >
            Confirm Land Size
         </button>
      </div>
    </div>
  );
